        let pace2_key = "₢ABAAB".to_string();
        let pace2 = Pace {
            silks: "second-pace".to_string(),
            tacks: vec![make_valid_tack(PaceState::Rough, None)],
        };
        heat.paces.insert(pace2_key.clone(), pace2);
